// Orquesta: Geocoding -> Google Solar API (buildingInsights + shade) -> Claude fallback
// Requiere env: GOOGLE_API_KEY, ANTHROPIC_API_KEY
// Input en body: { address?, lat?, lon? }

const src = $input.first().json;
const body = src.body || src;
const inAddress = (body.address || '').toString().trim();
let lat = body.lat != null ? Number(body.lat) : null;
let lon = body.lon != null ? Number(body.lon) : null;
if (!inAddress && (lat == null || lon == null)) {
  throw new Error('address o lat/lon requeridos');
}

const GKEY = $env.GOOGLE_API_KEY;
const AKEY = $env.ANTHROPIC_API_KEY;
if (!GKEY) throw new Error('Falta env GOOGLE_API_KEY');

// 1) Geocoding si no hay coords
let resolvedAddress = inAddress;
if (lat == null || lon == null) {
  const geo = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://maps.googleapis.com/maps/api/geocode/json',
    qs: { address: inAddress, key: GKEY },
    json: true,
  });
  if (!geo.results || !geo.results.length) {
    throw new Error('Geocoding sin resultados para: ' + inAddress);
  }
  const top = geo.results[0];
  lat = top.geometry.location.lat;
  lon = top.geometry.location.lng;
  resolvedAddress = top.formatted_address || inAddress;
}

// 2) Google Solar API buildingInsights
let solar = null;
try {
  solar = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://solar.googleapis.com/v1/buildingInsights:findClosest',
    qs: {
      'location.latitude': lat,
      'location.longitude': lon,
      requiredQuality: 'LOW',
      key: GKEY,
    },
    json: true,
  });
} catch (e) {
  solar = null;
}

const sp = solar && solar.solarPotential;
if (sp) {
  const areaM2 = sp.maxArrayAreaMeters2 != null ? Number(sp.maxArrayAreaMeters2) : null;
  const maxPanels = sp.maxArrayPanelsCount != null ? Number(sp.maxArrayPanelsCount) : null;
  const sunshine = sp.maxSunshineHoursPerYear != null ? Number(sp.maxSunshineHoursPerYear) : null;
  let tiltDeg = null, azimuthDeg = null;
  const configs = sp.solarPanelConfigs || [];
  const best = configs.reduce((a, b) => (b.panelsCount > (a?.panelsCount || 0) ? b : a), null);
  const panels = (sp.solarPanels || []);
  if (panels.length) {
    const p0 = panels[0];
    tiltDeg = p0.orientation === 'LANDSCAPE' ? 10 : 15;
  }
  const roofSegs = sp.roofSegmentStats || [];
  if (roofSegs.length) {
    let sumArea = 0, sumAz = 0, sumPitch = 0;
    for (const s of roofSegs) {
      const a = s.stats?.areaMeters2 || 0;
      sumArea += a;
      sumAz += (s.azimuthDegrees || 0) * a;
      sumPitch += (s.pitchDegrees || 0) * a;
    }
    if (sumArea > 0) {
      azimuthDeg = Math.round(sumAz / sumArea);
      tiltDeg = Math.round(sumPitch / sumArea);
    }
  }

  // Shade index — deriva del dataset de paneles potenciales.
  // Cada panel trae yearlyEnergyDcKwh (producción anual con sombra real).
  // shadeIndex = promedio(top-N paneles usados) / max(yearlyEnergyDcKwh)
  // Valor 1.0 = sin sombra; 0.8 = 20% de sombra efectiva.
  let shadeIndex = null;
  let shadeSource = null;
  const energies = panels.map(p => Number(p.yearlyEnergyDcKwh || 0)).filter(v => v > 0);
  if (energies.length && best?.panelsCount) {
    const sorted = [...energies].sort((a, b) => b - a);
    const topN = sorted.slice(0, Math.min(best.panelsCount, sorted.length));
    const avgTop = topN.reduce((s, v) => s + v, 0) / topN.length;
    const maxE = sorted[0];
    if (maxE > 0) {
      shadeIndex = Math.max(0.1, Math.min(1, avgTop / maxE));
      shadeSource = 'google-datalayers';
    }
  }

  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2, maxPanels, tiltDeg, azimuthDeg,
    sunshineHoursYear: sunshine,
    shadeIndex, shadeSource,
    source: 'google',
    confidence: 0.85,
    notes: best ? `config ${best.panelsCount} paneles${shadeIndex != null ? ` · sombra ${Math.round((1 - shadeIndex) * 100)}%` : ''}` : '',
  } }];
}

// 3) Fallback Claude — estimación por ubicación
if (!AKEY) {
  return [{ json: {
    lat, lon, address: resolvedAddress,
    areaM2: null, tiltDeg: 10, azimuthDeg: 180,
    shadeIndex: null, shadeSource: null,
    source: 'none', confidence: 0,
    notes: 'Solar API sin datos y ANTHROPIC_API_KEY no configurada',
  } }];
}
const prompt = `Eres un ingeniero solar FV en Colombia. Estima el área útil de techo en m² para paneles fotovoltaicos en esta ubicación residencial/comercial típica y un factor de sombreado aproximado.

Dirección: ${resolvedAddress}
Coordenadas: ${lat}, ${lon}

Devuelve SOLO JSON válido con esta forma exacta:
{"areaM2": number, "tiltDeg": number, "azimuthDeg": number, "shadeIndex": number_0_to_1, "confidence": number_0_to_1, "notes": string}

Reglas:
- Si no tienes contexto, asume vivienda promedio 40-80 m² de techo útil.
- Azimuth 0=Norte, 90=Este, 180=Sur, 270=Oeste. En Colombia preferir ~180° con tilt 8-12°.
- shadeIndex: 1.0 = sin sombra; 0.9-0.95 típico zona abierta; 0.8-0.85 con árboles o vecinos altos; < 0.8 sombra significativa. Estima conservador.`;

const claude = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.anthropic.com/v1/messages',
  headers: {
    'x-api-key': AKEY,
    'anthropic-version': '2023-06-01',
    'content-type': 'application/json',
  },
  body: {
    model: 'claude-sonnet-4-6',
    max_tokens: 512,
    messages: [{ role: 'user', content: prompt }],
  },
  json: true,
});
const text = (claude.content || []).map(c => c.text || '').join('\n').trim();
const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Claude no devolvió JSON parseable');
let parsed;
try { parsed = JSON.parse(m[0]); } catch (e) { throw new Error('JSON inválido de Claude: ' + e.message); }

return [{ json: {
  lat, lon, address: resolvedAddress,
  areaM2: parsed.areaM2 != null ? Number(parsed.areaM2) : null,
  tiltDeg: parsed.tiltDeg != null ? Number(parsed.tiltDeg) : 10,
  azimuthDeg: parsed.azimuthDeg != null ? Number(parsed.azimuthDeg) : 180,
  shadeIndex: parsed.shadeIndex != null ? Number(parsed.shadeIndex) : null,
  shadeSource: parsed.shadeIndex != null ? 'claude-estimate' : null,
  source: 'claude',
  confidence: parsed.confidence != null ? Number(parsed.confidence) : 0.4,
  notes: parsed.notes || '',
} }];
